class Node:
 """Represents a node in the binary tree"""
 def __init__(self, key):
 self.key = key
 self.left = None
 self.right = None

class BST:
 """Binary Search Tree with insert, search, and traversal operations"""
 def __init__(self):
 self.root = None

 def insert(self, key):
 """Insert a new key into the BST"""
 self.root = self._insert_recursive(self.root, key)

 def _insert_recursive(self, node, key):
 # Base case: empty position found
 if node is None:
 return Node(key)

 # Recursive case: go left or right based on key value
 if key < node.key:
 node.left = self._insert_recursive(node.left, key)
 else:
 node.right = self._insert_recursive(node.right, key)

 return node

 def search(self, key):
 """Search for a key in the BST - returns True if found"""
 return self._search_recursive(self.root, key)

 def _search_recursive(self, node, key):
 # Base case: node is null or key found
 if node is None or node.key == key:
 return node is not None

 # Recursive case: search in appropriate subtree
 if key < node.key:
 return self._search_recursive(node.left, key)
 return self._search_recursive(node.right, key)

 def inorder(self):
 """In-order traversal - returns sorted list for BST"""
 result = []
 self._inorder_recursive(self.root, result)
 return result

 def _inorder_recursive(self, node, result):
 if node:
 self._inorder_recursive(node.left, result)
 result.append(node.key)
 self._inorder_recursive(node.right, result)

 def height(self):
 """Calculate height of the tree"""
 return self._height_recursive(self.root)

 def _height_recursive(self, node):
 if node is None:
 return -1 # Empty tree has height -1

 left_height = self._height_recursive(node.left)
 right_height = self._height_recursive(node.right)

 return 1 + max(left_height, right_height)

# Demo usage
if __name__ == "__main__":
 bst = BST()

 # Insert nodes
 for value in [8, 3, 10, 1, 6, 14, 4, 7, 13]:
 bst.insert(value)

 print("In-order traversal (sorted):", bst.inorder())
 print("Search for 6:", bst.search(6))
 print("Search for 5:", bst.search(5))
 print("Tree height:", bst.height())

#include <stdio.h>
#include <stdlib.h>

// Node structure for binary tree
struct Node {
 int data;
 struct Node* left;
 struct Node* right;
};

// Create a new node
struct Node* createNode(int data) {
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = data;
 newNode->left = NULL;
 newNode->right = NULL;
 return newNode;
}

// Pre-order traversal: Root -> Left -> Right
void preOrder(struct Node* root) {
 if (root == NULL) return;

 printf("%d ", root->data); // Visit root
 preOrder(root->left); // Traverse left
 preOrder(root->right); // Traverse right
}

// In-order traversal: Left -> Root -> Right
void inOrder(struct Node* root) {
 if (root == NULL) return;

 inOrder(root->left); // Traverse left
 printf("%d ", root->data); // Visit root
 inOrder(root->right); // Traverse right
}

// Post-order traversal: Left -> Right -> Root
void postOrder(struct Node* root) {
 if (root == NULL) return;

 postOrder(root->left); // Traverse left
 postOrder(root->right); // Traverse right
 printf("%d ", root->data); // Visit root
}

// Calculate tree height
int height(struct Node* root) {
 if (root == NULL) return -1;

 int leftHeight = height(root->left);
 int rightHeight = height(root->right);

 return 1 + (leftHeight > rightHeight ? leftHeight : rightHeight);
}

// Count total nodes
int countNodes(struct Node* root) {
 if (root == NULL) return 0;
 return 1 + countNodes(root->left) + countNodes(root->right);
}

int main() {
 /*
 8
 / \
 3 10
 / \ \
 1 6 14
 / \ /
 4 7 13
 */

 // Build the tree
 struct Node* root = createNode(8);
 root->left = createNode(3);
 root->right = createNode(10);
 root->left->left = createNode(1);
 root->left->right = createNode(6);
 root->right->right = createNode(14);
 root->left->right->left = createNode(4);
 root->left->right->right = createNode(7);
 root->right->right->left = createNode(13);

 printf("Tree Statistics:\n");
 printf("Total nodes: %d\n", countNodes(root));
 printf("Tree height: %d\n", height(root));

 printf("\nPre-order (Root-Left-Right):\n");
 preOrder(root);

 printf("\n\nIn-order (Left-Root-Right):\n");
 inOrder(root);

 printf("\n\nPost-order (Left-Right-Root):\n");
 postOrder(root);

 printf("\n");

 return 0;
}

class TreeNode:
 """Node class for BST"""
 def __init__(self, key):
 self.key = key
 self.left = None
 self.right = None

class BST:
 """Binary Search Tree with complete operations"""

 def __init__(self):
 self.root = None

 def insert(self, key):
 """Insert key maintaining BST property"""
 self.root = self._insert(self.root, key)

 def _insert(self, node, key):
 if node is None:
 return TreeNode(key)

 if key < node.key:
 node.left = self._insert(node.left, key)
 elif key > node.key:
 node.right = self._insert(node.right, key)
 # If key == node.key, do nothing (no duplicates)
 return node

 def search(self, key):
 """Iterative search - returns node if found"""
 current = self.root
 while current:
 if key == current.key:
 return current
 elif key < current.key:
 current = current.left
 else:
 current = current.right
 return None

 def delete(self, key):
 """Delete key from BST"""
 self.root = self._delete(self.root, key)

 def _delete(self, node, key):
 if node is None:
 return None

 if key < node.key:
 node.left = self._delete(node.left, key)
 elif key > node.key:
 node.right = self._delete(node.right, key)
 else:
 # Case 1: Leaf node - simply remove
 if node.left is None and node.right is None:
 return None

 # Case 2: One child - replace with child
 if node.left is None:
 return node.right
 if node.right is None:
 return node.left

 # Case 3: Two children - find inorder successor
 successor = self._find_min(node.right)
 node.key = successor.key
 node.right = self._delete(node.right, successor.key)

 return node

 def _find_min(self, node):
 """Find node with minimum key in subtree"""
 current = node
 while current.left:
 current = current.left
 return current

 def find_max(self):
 """Find maximum key in BST"""
 if self.root is None:
 return None
 current = self.root
 while current.right:
 current = current.right
 return current.key

 def find_min(self):
 """Find minimum key in BST"""
 if self.root is None:
 return None
 current = self.root
 while current.left:
 current = current.left
 return current.key

# Demonstration
if __name__ == "__main__":
 bst = BST()

 # Build tree: 50, 30, 70, 20, 40, 60, 80
 for val in [50, 30, 70, 20, 40, 60, 80]:
 bst.insert(val)

 print("Initial BST values:")
 def inorder(node):
 if node:
 inorder(node.left)
 print(node.key, end=' ')
 inorder(node.right)
 inorder(bst.root)
 print()

 print("Min:", bst.find_min()) # 20
 print("Max:", bst.find_max()) # 80
 print("Search 40:", bst.search(40) is not None) # True

 # Delete leaf node (20)
 bst.delete(20)
 print("After deleting 20:", end=' ')
 inorder(bst.root)
 print()

 # Delete node with one child (30)
 bst.delete(30)
 print("After deleting 30:", end=' ')
 inorder(bst.root)
 print()

 # Delete node with two children (50 - root)
 bst.delete(50)
 print("After deleting 50 (root):", end=' ')
 inorder(bst.root)
 print()
